import java.io.*;import java.util.*;// Reservation (Serializable)class Reservation implements Serializable {    private static final long serialVersionUID = 1L;    private String reservationId;    private String customerName;    private String roomType;    public Reservation(String reservationId, String customerName, String roomType) {        this.reservationId = reservationId;        this.customerName = customerName;        this.roomType = roomType;    }    @Override    public String toString() {        return "Reservation ID: " + reservationId +                ", Customer: " + customerName +                ", Room Type: " + roomType;    }}// Wrapper class for persistenceclass SystemState implements Serializable {    private static final long serialVersionUID = 1L;    List<Reservation> reservations;    Map<String, Integer> inventory;    public SystemState(List<Reservation> reservations, Map<String, Integer> inventory) {        this.reservations = reservations;        this.inventory = inventory;    }}// Persistence Serviceclass PersistenceService {    private static final String FILE_NAME = "system_state.dat";    // Save state to file    public static void save(SystemState state) {        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(FILE_NAME))) {            oos.writeObject(state);            System.out.println("System state saved successfully.");        } catch (IOException e) {            System.out.println("Error saving system state: " + e.getMessage());        }    }    // Load state from file    public static SystemState load() {        File file = new File(FILE_NAME);        if (!file.exists()) {            System.out.println("No previous state found. Starting fresh.");            return null;        }        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(FILE_NAME))) {            SystemState state = (SystemState) ois.readObject();            System.out.println("System state loaded successfully.");            return state;        } catch (IOException | ClassNotFoundException e) {            System.out.println("Error loading state. Starting with clean state.");            return null;        }    }}// Main Systempublic class UseCase12DataPersistenceRecovery {    public static void main(String[] args) {        List<Reservation> reservations;        Map<String, Integer> inventory;        // Step 1: Load persisted state (Recovery)        SystemState loadedState = PersistenceService.load();        if (loadedState != null) {            reservations = loadedState.reservations;            inventory = loadedState.inventory;        } else {            // Initialize fresh state            reservations = new ArrayList<>();            inventory = new HashMap<>();            inventory.put("Standard", 2);            inventory.put("Deluxe", 2);            inventory.put("Suite", 1);        }        // Step 2: Simulate operations        reservations.add(new Reservation("R001", "Alice", "Deluxe"));        inventory.put("Deluxe", inventory.get("Deluxe") - 1);        reservations.add(new Reservation("R002", "Bob", "Suite"));        inventory.put("Suite", inventory.get("Suite") - 1);        // Step 3: Display current state        System.out.println("\n--- Current Reservations ---");        for (Reservation r : reservations) {            System.out.println(r);        }        System.out.println("\n--- Current Inventory ---");        System.out.println(inventory);        // Step 4: Save state before shutdown        SystemState currentState = new SystemState(reservations, inventory);        PersistenceService.save(currentState);        System.out.println("\nShutdown complete. Restart program to test recovery.");    }}